import React, { useState } from "react";
import { ArrowLeft } from "lucide-react";

export default function PinScreen({ onConfirm, onBack, darkMode }) {
  const [pinInput, setPinInput] = useState("");
  const [error, setError] = useState(null);

  const handleConfirm = () => {
    if (pinInput.length === 0) {
      setError("Enter your PIN");
      return;
    }

    const success = onConfirm(pinInput);
    if (!success) {
      setError("Incorrect PIN");
    } else {
      setError(null);
      setPinInput("");
    }
  };

  return (
    <div
      className={`min-h-screen px-5 pt-6 pb-24 flex flex-col items-center ${
        darkMode ? "bg-gray-900" : "bg-[#f4f6fb]"
      }`}
    >
      {/* Header */}
      <div className="flex items-center gap-3 mb-8 w-full">
        <button onClick={onBack}>
          <ArrowLeft
            className={`w-6 h-6 ${darkMode ? "text-gray-300" : "text-gray-700"}`}
          />
        </button>
        <h1
          className={`text-xl font-semibold ${
            darkMode ? "text-white" : "text-gray-900"
          }`}
        >
          Enter PIN
        </h1>
      </div>

      {/* PIN Input */}
      <div
        className={`w-full max-w-sm rounded-2xl p-6 shadow-sm ${
          darkMode ? "bg-gray-800 shadow-gray-700" : "bg-white shadow-sm"
        }`}
      >
        <label
          className={`text-sm ${darkMode ? "text-gray-400" : "text-gray-500"}`}
        >
          PIN
        </label>
        <input
          type="password"
          placeholder="Enter your PIN"
          value={pinInput}
          onChange={(e) => setPinInput(e.target.value)}
          className={`mt-3 w-full text-2xl font-semibold outline-none border-b pb-2 ${
            darkMode
              ? "border-gray-600 text-white placeholder-gray-400 bg-gray-800"
              : "border-gray-300 text-gray-900 placeholder-gray-400 bg-white"
          }`}
        />

        {error && <p className="mt-3 text-sm text-red-500">{error}</p>}

        <button
          onClick={handleConfirm}
          className="mt-8 w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold active:scale-[0.98] transition"
        >
          Confirm
        </button>
      </div>
    </div>
  );
}
